script:
frappe.ui.form.on("Purchase Receipt Item", {
  item_code(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.item_code) return;

    frappe.db.get_value("Item", row.item_code, "custom_is_reconfigurable")
      .then(r => {
        const is_reconf = (r.message && r.message.custom_is_reconfigurable) ? 1 : 0;
        
        frappe.db.get_value("Item", row.item_code, "custom_sheet_length_mm")
        .then(r => {
          
          frappe.model.set_value(cdt, cdn, "custom_sheet_length_mm", r.message.custom_sheet_length_mm);
          
        });
        frappe.db.get_value("Item", row.item_code, "custom_sheet_width_mm")
        .then(r => {
          
          frappe.model.set_value(cdt, cdn, "custom_sheet_width_mm", r.message.custom_sheet_width_mm);
          
        });

      });
  }
});

frappe.ui.form.on("Purchase Receipt", {
  validate(frm) {
    (frm.doc.items || []).forEach(row => {
      if (!row.item_code) return;

      // Quick client-side check; server-side will enforce strictly
      // (avoid async call here).
      if (row.custom_sheet_length_mm && row.custom_sheet_width_mm) return;
    });
  }
});

frappe.ui.form.on('Sales Order', {
	refresh(frm) {
		// your code here
	}
});

frappe.ui.form.on("Sales Order Item", {
  item_code(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.item_code) return;

    frappe.db.get_value("Item", row.item_code, "custom_requires_dimensions")
      .then(r => {
        const needs_dim = (r.message && r.message.custom_requires_dimensions) ? 1 : 0;
        if (!needs_dim) return;

        if (!row.custom_client_length_mm) {
          frappe.db.get_value("Item", row.item_code, "custom_client_length_mm")
            .then(r => {
              frappe.model.set_value(cdt, cdn, "custom_client_length_mm", r.message.custom_client_length_mm);
            });
        }

        if (!row.custom_client_width_mm) {
          frappe.db.get_value("Item", row.item_code, "custom_client_width_mm")
            .then(r => {
              frappe.model.set_value(cdt, cdn, "custom_client_width_mm", r.message.custom_client_width_mm);
            });
        }
      });
  }
});

frappe.ui.form.on("Quotation Item", {
    item_code: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        frappe.db.get_value("Item", row.item_code,
            ["custom_item_types", "custom_is_composite"],
            function(r) {

                frappe.model.set_value(cdt, cdn, "custom_item_type", r.custom_item_type);

                if (r.custom_item_type === "SERVICE") {
                    frappe.model.set_value(cdt, cdn, "custom_is_service_row", 1);
                }

                if (r.custom_item_type === "ACCESSOIRE") {
                    frappe.model.set_value(cdt, cdn, "custom_is_accessory_row", 1);
                }
            }
        );
    }
});

frappe.ui.form.on("Quotation", {
    refresh(frm) {
        frm.refresh_field("items");
    },

    validate(frm) {
        (frm.doc.items || []).forEach((row) => {
            if (row.custom_is_service_row && !row.custom_parent_row) {
                frappe.throw(
                    __("Service row {0} must have a parent row.", [row.idx || "?"])
                );
            }

            if (
                ["DECOUPE", "OUVRAGE"].includes(row.custom_item_types) &&
                !row.custom_is_service_row &&
                !row.custom_is_accessory_row
            ) {
                if (!flt_safe(row.custom_client_length_mm) || !flt_safe(row.custom_client_width_mm)) {
                    frappe.throw(
                        __("Length and Width are required for row {0}.", [row.idx || "?"])
                    );
                }
            }
        });
    }
});

frappe.ui.form.on("Quotation Item", {
    item_code: async function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        if (!row.item_code) {
            await clear_item_type_flags(cdt, cdn);
            frm.refresh_field("items");
            return;
        }

        try {
            const r = await frappe.db.get_value("Item", row.item_code, [
                "custom_item_types",
                "custom_requires_dimensions"
            ]);

            const item_type = r.message?.custom_item_types || "";
            const requires_dimensions = cint_safe(r.message?.custom_requires_dimensions || 0);

            await frappe.model.set_value(cdt, cdn, "custom_item_types", item_type);

            if (!row.custom_parent_row) {
                await frappe.model.set_value(cdt, cdn, "custom_is_service_row", 0);
                await frappe.model.set_value(cdt, cdn, "custom_is_accessory_row", 0);
            }

            toggle_dimension_reqd(frm, item_type, requires_dimensions);
            frm.refresh_field("items");
        } catch (e) {
            console.error("Unable to fetch Item type", e);
        }
    },

    custom_services_btn: function (frm, cdt, cdn) {
        const row = locals[cdt][cdn];

        if (!can_add_services(row)) {
            frappe.msgprint(__("Services are not allowed on this row."));
            return;
        }

        open_services_dialog(frm, row);
    },

    form_render(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        toggle_dimension_reqd(frm, row.custom_item_types || "", null);
        frm.refresh_field("items");
    }
});

async function clear_item_type_flags(cdt, cdn) {
    await frappe.model.set_value(cdt, cdn, "custom_item_types", "");
    await frappe.model.set_value(cdt, cdn, "custom_is_service_row", 0);
    await frappe.model.set_value(cdt, cdn, "custom_is_accessory_row", 0);
    await frappe.model.set_value(cdt, cdn, "custom_parent_row", "");
}

function can_add_services(row) {
    return Boolean(
        row.item_code &&
        !row.custom_is_service_row &&
        !row.custom_is_accessory_row &&
        ["DECOUPE", "OUVRAGE"].includes(row.custom_item_types)
    );
}

function toggle_dimension_reqd(frm, item_type, requires_dimensions = null) {
    const must_have_dimensions =
        ["DECOUPE", "OUVRAGE"].includes(item_type) || cint_safe(requires_dimensions);

    const length_df = frappe.meta.get_docfield(
        "Quotation Item",
        "custom_client_length_mm",
        frm.doc.name
    );
    const width_df = frappe.meta.get_docfield(
        "Quotation Item",
        "custom_client_width_mm",
        frm.doc.name
    );

    if (length_df) length_df.reqd = must_have_dimensions ? 1 : 0;
    if (width_df) width_df.reqd = must_have_dimensions ? 1 : 0;

    frm.refresh_field("items");
}

async function open_services_dialog(frm, parent_row) {
    const length_mm = flt_safe(parent_row.custom_client_length_mm);
    const width_mm = flt_safe(parent_row.custom_client_width_mm);
    const qty = flt_safe(parent_row.qty || 1);

    const surface_m2 =
        length_mm && width_mm ? (length_mm * width_mm) / 1000000 : 0;

    const perimeter_m =
        length_mm && width_mm ? ((length_mm + width_mm) * 2) / 1000 : 0;

    let services = [];
    try {
        const r = await frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Item",
                fields: [
                    "name",
                    "item_name",
                    "custom_item_types",
                    "custom_service_calc_basis",
                    "custom_service_fixed_qty"
                ],
                filters: [
                    ["Item", "custom_item_types", "in", ["SERVICE", "ACCESSOIRE"]],
                    ["Item", "disabled", "=", 0]
                ],
                limit_page_length: 500,
                order_by: "item_name asc"
            }
        });

        services = r.message || [];
    } catch (e) {
        console.error("Unable to load services/accessories", e);
        frappe.msgprint(__("Unable to load services/accessories list."));
        return;
    }

    const all_rows = services.map((svc) => {
        const item_type = svc.custom_item_types || "";
        const basis = svc.custom_service_calc_basis || "MANUEL";
        const fixed_qty = flt_safe(svc.custom_service_fixed_qty || 0);

        let calculated_qty = 0;
        let final_qty = 0;

        if (item_type === "ACCESSOIRE") {
            calculated_qty = 0;
            final_qty = 0;
        } else if (basis === "SURFACE") {
            calculated_qty = surface_m2 * qty;
            final_qty = calculated_qty;
        } else if (basis === "PERIMETRE") {
            calculated_qty = perimeter_m * qty;
            final_qty = calculated_qty;
        } else if (basis === "PIECE") {
            calculated_qty = qty;
            final_qty = calculated_qty;
        } else if (basis === "FIXE") {
            calculated_qty = fixed_qty || 1;
            final_qty = calculated_qty;
        } else {
            calculated_qty = 0;
            final_qty = 0;
        }

        return {
            service_item: svc.name,
            service_label: svc.item_name || svc.name,
            item_type: item_type,
            calculation_basis: item_type === "ACCESSOIRE" ? "MANUEL" : basis,
            calculated_qty: calculated_qty,
            final_qty: final_qty
        };
    });

    const page_length = 8;
    let current_page = 1;
    let filtered_rows = [...all_rows];
    let d = null;

    function apply_filters() {
        if (!d) return;

        const show_services = cint_safe(d.get_value("show_services")) === 1;
        const show_accessories = cint_safe(d.get_value("show_accessories")) === 1;
        const search_text = (d.get_value("search_text") || "").trim().toLowerCase();

        filtered_rows = all_rows.filter((row) => {
            const type_ok =
                (show_services && row.item_type === "SERVICE") ||
                (show_accessories && row.item_type === "ACCESSOIRE");

            if (!type_ok) return false;

            if (!search_text) return true;

            return (
                (row.service_item || "").toLowerCase().includes(search_text) ||
                (row.service_label || "").toLowerCase().includes(search_text) ||
                (row.calculation_basis || "").toLowerCase().includes(search_text)
            );
        });

        current_page = 1;
        render_page();
    }

    function render_page() {
        if (!d) return;

        const total_rows = filtered_rows.length;
        const total_pages = Math.max(1, Math.ceil(total_rows / page_length));

        if (current_page > total_pages) current_page = total_pages;
        if (current_page < 1) current_page = 1;

        const start = (current_page - 1) * page_length;
        const end = start + page_length;
        const page_rows = filtered_rows.slice(start, end);

        const table_field = d.fields_dict.service_table;
        table_field.df.data = page_rows;
        table_field.grid.refresh();

        if (table_field.grid && table_field.grid.wrapper) {
            $(table_field.grid.wrapper).css({
                "max-height": "340px",
                "overflow-y": "auto"
            });
        }

        const page_info = total_rows
            ? __("Page {0} of {1} ({2} items)", [current_page, total_pages, total_rows])
            : __("No items found");

        d.fields_dict.page_info.$wrapper.html(`
            <div style="padding-top: 6px; white-space: nowrap;">
                ${frappe.utils.escape_html(page_info)}
            </div>
        `);
    }

    d = new frappe.ui.Dialog({
        title: __("Services / Accessoires"),
        size: "extra-large",
        fields: [
            {
                fieldtype: "HTML",
                fieldname: "context_html"
            },

            {
                fieldtype: "Section Break"
            },
            {
                fieldtype: "Check",
                fieldname: "show_services",
                label: __("Services"),
                default: 1,
                onchange: function () {
                    apply_filters();
                }
            },
            {
                fieldtype: "Check",
                fieldname: "show_accessories",
                label: __("Accessoires"),
                default: 1,
                onchange: function () {
                    apply_filters();
                }
            },
            {
                fieldtype: "Data",
                fieldname: "search_text",
                label: __("Recherche"),
                onchange: function () {
                    apply_filters();
                }
            },

            {
                fieldtype: "Section Break"
            },
            {
                fieldtype: "Table",
                fieldname: "service_table",
                cannot_add_rows: true,
                in_place_edit: true,
                data: [],
                fields: [
                    {
                        fieldtype: "Data",
                        fieldname: "service_item",
                        in_list_view: 1,
                        label: __("Code"),
                        read_only: 1,
                        hidden: 1,
                        columns: 2
                    },
                    {
                        fieldtype: "Data",
                        fieldname: "service_label",
                        in_list_view: 1,
                        label: __("Article"),
                        read_only: 1,
                        columns: 4
                    },
                    {
                        fieldtype: "Data",
                        fieldname: "item_type",
                        in_list_view: 1,
                        label: __("Type"),
                        read_only: 1,
                        columns: 2
                    },
                    {
                        fieldtype: "Data",
                        fieldname: "calculation_basis",
                        in_list_view: 1,
                        label: __("Base"),
                        read_only: 1,
                        columns: 2
                    },
                    {
                        fieldtype: "Float",
                        fieldname: "calculated_qty",
                        in_list_view: 1,
                        label: __("Calculated Qty"),
                        read_only: 1,
                        hidden: 1,
                        columns: 2
                    },
                    {
                        fieldtype: "Float",
                        fieldname: "final_qty",
                        in_list_view: 1,
                        label: __("Final Qty"),
                        columns: 2
                    }
                ]
            },

            {
                fieldtype: "Section Break"
            },
            {
                fieldtype: "Button",
                fieldname: "prev_page",
                label: __("Previous"),
                click: function () {
                    current_page--;
                    render_page();
                }
            },
            {
                fieldtype: "Button",
                fieldname: "next_page",
                label: __("Next"),
                click: function () {
                    current_page++;
                    render_page();
                }
            },
            {
                fieldtype: "HTML",
                fieldname: "page_info"
            }
        ],
        primary_action_label: __("Insert Selected Items"),
        primary_action: async function() {
            const grid = d.fields_dict.service_table.grid;
            const selected = grid.get_selected_children();

            if (!selected.length) {
                frappe.msgprint(__("Please select at least one row."));
                return;
            }

            try {
                d.set_primary_action(__("Inserting..."), null);
                d.$wrapper.addClass("modal-busy");
                frappe.dom.freeze(__("Inserting selected items..."));

                for (const svc of selected) {
                    await insert_service_row(frm, parent_row, {
                        service_item: svc.service_item,
                        final_qty: svc.final_qty,
                        item_type: svc.item_type
                    });
                }

                d.hide();
                frm.refresh_field("items");
            } catch (e) {
                console.error("Unable to insert selected items", e);
                frappe.msgprint(__("Unable to insert selected items."));
            } finally {
                frappe.dom.unfreeze();
                d.$wrapper.removeClass("modal-busy");
                d.set_primary_action(__("Insert Selected Items"), async function() {
                    const grid = d.fields_dict.service_table.grid;
                    const selected = grid.get_selected_children();

                    if (!selected.length) {
                        frappe.msgprint(__("Please select at least one row."));
                        return;
                    }

                    try {
                        d.set_primary_action(__("Inserting..."), null);
                        d.$wrapper.addClass("modal-busy");
                        frappe.dom.freeze(__("Inserting selected items..."));

                        for (const svc of selected) {
                            await insert_service_row(frm, parent_row, {
                                service_item: svc.service_item,
                                final_qty: svc.final_qty,
                                item_type: svc.item_type
                            });
                        }

                        d.hide();
                        frm.refresh_field("items");
                    } catch (e) {
                        console.error("Unable to insert selected items", e);
                        frappe.msgprint(__("Unable to insert selected items."));
                    } finally {
                        frappe.dom.unfreeze();
                        d.$wrapper.removeClass("modal-busy");
                    }
                });
            }
        }
    });

    d.fields_dict.context_html.$wrapper.html(`
        <div style="margin-bottom: 16px;">
            <table class="table table-bordered" style="margin-bottom: 12px;">
                <thead>
                    <tr>
                        <th colspan="6">${__("Parent Item Context")}</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <th>${__("Article")}</th>
                        <td>${frappe.utils.escape_html(parent_row.item_code || "")}</td>
                        <th>${__("Length")}</th>
                        <td>${length_mm}</td>
                        <th>${__("Width")}</th>
                        <td>${width_mm}</td>
                    </tr>
                    <tr>
                        <th>${__("Qty")}</th>
                        <td>${qty}</td>
                        <th>${__("Surface")}</th>
                        <td>${surface_m2.toFixed(4)} m²</td>
                        <th>${__("Perimeter")}</th>
                        <td>${perimeter_m.toFixed(4)} m</td>
                    </tr>
                </tbody>
            </table>
        </div>
    `);

    d.show();

    setTimeout(() => {
        const services_wrap = d.fields_dict.show_services?.wrapper;
        const accessories_wrap = d.fields_dict.show_accessories?.wrapper;
        const search_wrap = d.fields_dict.search_text?.wrapper;
        const prev_wrap = d.fields_dict.prev_page?.wrapper;
        const next_wrap = d.fields_dict.next_page?.wrapper;
        const page_info_wrap = d.fields_dict.page_info?.wrapper;
        const table_wrap = d.fields_dict.service_table?.wrapper;

        if (services_wrap && accessories_wrap && search_wrap) {
            const row_top = $('<div style="display:flex; align-items:flex-end; gap:16px; flex-wrap:nowrap; margin-bottom:12px;"></div>');
            $(services_wrap).css({
                "margin-bottom": "0",
                "flex": "0 0 auto"
            });
            $(accessories_wrap).css({
                "margin-bottom": "0",
                "flex": "0 0 auto"
            });
            $(search_wrap).css({
                "margin-bottom": "0",
                "flex": "1 1 auto"
            });

            row_top.append(services_wrap);
            row_top.append(accessories_wrap);
            row_top.append(search_wrap);

            $(table_wrap).before(row_top);
        }

        if (prev_wrap && next_wrap && page_info_wrap && table_wrap) {
            const row_bottom = $('<div style="display:flex; align-items:center; gap:12px; flex-wrap:nowrap; margin-top:10px;"></div>');
            $(prev_wrap).css({
                "margin-bottom": "0",
                "flex": "0 0 auto"
            });
            $(next_wrap).css({
                "margin-bottom": "0",
                "flex": "0 0 auto"
            });
            $(page_info_wrap).css({
                "margin-bottom": "0",
                "flex": "0 0 auto"
            });

            row_bottom.append(prev_wrap);
            row_bottom.append(next_wrap);
            row_bottom.append(page_info_wrap);

            $(table_wrap).after(row_bottom);
        }

        apply_filters();
    }, 50);
}

async function insert_service_row(frm, parent_row, values) {
    const row = frm.add_child("items");

    row.item_code = values.service_item;

    const r = await frappe.db.get_value("Item", row.item_code, "item_name");
    const base_name = r.message?.item_name || row.item_code;

    const r2 = await frappe.db.get_value("Item", row.item_code, "stock_uom");

    const is_service = values.item_type === "SERVICE";
    const is_accessory = values.item_type === "ACCESSOIRE";

    row.item_name = base_name;
    row.description = base_name;
    row.qty = flt_safe(values.final_qty);
    row.uom = r2.message?.stock_uom || "";
    row.custom_parent_row = parent_row.name;
    row.custom_is_service_row = is_service ? 1 : 0;
    row.custom_is_accessory_row = is_accessory ? 1 : 0;
    row.custom_item_types = values.item_type || "";
    row.custom_client_length_mm = 0;
    row.custom_client_width_mm = 0;

    if (frm.doc.selling_price_list) {
        try {
            const price_res = await frappe.db.get_list("Item Price", {
                fields: ["price_list_rate"],
                filters: {
                    item_code: row.item_code,
                    price_list: frm.doc.selling_price_list
                },
                limit: 1
            });

            if (price_res?.length) {
                const price = flt_safe(price_res[0].price_list_rate);
                row.price_list_rate = price;
                row.rate = price;
                row.amount = (price || 0) * (row.qty || 0);
            }
        } catch (e) {
            console.error("Unable to fetch Item Price", e);
        }
    }

    frm.refresh_field("items");
}

function flt_safe(v) {
    return flt(v || 0);
}

function cint_safe(v) {
    return cint(v || 0);
}

frappe.ui.form.on("Quotation Item", {

    custom_client_length_mm(frm, cdt, cdn) {
        update_item_name_with_dimensions(frm, cdt, cdn);
    },

    custom_client_width_mm(frm, cdt, cdn) {
        update_item_name_with_dimensions(frm, cdt, cdn);
    },
    custom_client_thickness_mm(frm, cdt, cdn) {
        update_item_name_with_dimensions(frm, cdt, cdn);
    },

    item_code(frm, cdt, cdn) {
        update_item_name_with_dimensions(frm, cdt, cdn);
    }

});


async function update_item_name_with_dimensions(frm, cdt, cdn) {

    const row = locals[cdt][cdn];

    if (!row.item_code) return;

    const length = flt(row.custom_client_length_mm || 0);
    const width = flt(row.custom_client_width_mm || 0);
    const thickness = flt(row.custom_client_thickness_mm || 0);

    if (!length || !width || !thickness) return;

    try {

        const r = await frappe.db.get_value("Item", row.item_code, "item_name");

        const base_name = r.message?.item_name || row.item_code;

        const new_name = `${base_name} ${thickness}MM [${length},${width}]`;

        frappe.model.set_value(cdt, cdn, "item_name", new_name);
        frappe.model.set_value(cdt, cdn, "description", new_name);

    } catch (e) {

        console.error("Unable to fetch Item name", e);

    }

}

frappe.ui.form.on("Serial No", {
    custom_dimension_length_mm(frm) {
        recalculate_geometry(frm);
    },

    custom_dimension_width_mm(frm) {
        recalculate_geometry(frm);
    }
});

function recalculate_geometry(frm) {
    const length = flt(frm.doc.custom_dimension_length_mm);
    const width = flt(frm.doc.custom_dimension_width_mm);

    if (length > 0 && width > 0) {
        frm.set_value("custom_surface_mm2", length * width);
        frm.set_value("custom_perimeter_mm", 2 * (length + width));
    } else {
        frm.set_value("custom_surface_mm2", 0);
        frm.set_value("custom_perimeter_mm", 0);
    }
}

frappe.ui.form.on("Delivery Note Item", {
    item_code(frm, cdt, cdn) {
        update_dimensioned_item_name(frm, cdt, cdn);
    },

    serial_and_batch_bundle(frm, cdt, cdn) {
        update_dimensioned_item_name(frm, cdt, cdn);
    },

    custom_client_length_mm(frm, cdt, cdn) {
        update_dimensioned_item_name(frm, cdt, cdn);
    },

    custom_client_width_mm(frm, cdt, cdn) {
        update_dimensioned_item_name(frm, cdt, cdn);
    },

