async function update_dimensioned_item_name(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.item_code) return;

    const item_r = await frappe.db.get_value(
        "Item",
        row.item_code,
        ["item_name", "custom_item_types"]
    );

    const item = item_r && item_r.message ? item_r.message : {};
    const base_name = item.item_name || row.item_name || "";
    const item_type = item.custom_item_types || "";

    let length = 0;
    let width = 0;
    let thickness = 0;

    // Cas DECOUPE: dimensions depuis le bundle -> premier serial
    if (item_type === "DECOUPE" && row.serial_and_batch_bundle) {
        try {
            const bundle = await frappe.db.get_doc(
                "Serial and Batch Bundle",
                row.serial_and_batch_bundle
            );

            const first_entry = (bundle.entries || []).find(d => d.serial_no);
            if (first_entry && first_entry.serial_no) {
                const serial = await frappe.db.get_doc("Serial No", first_entry.serial_no);

                length = flt(serial.custom_dimension_length_mm);
                width = flt(serial.custom_dimension_width_mm);
                thickness = flt(serial.custom_dimension_thickness_mm);
            }
        } catch (e) {
            console.error("Failed to read bundle/serial dimensions", e);
        }
    } else {
        // Cas non-DECOUPE: dimensions manuelles depuis la ligne
        length = flt(row.custom_client_length_mm || row.custom_dimension_length_mm);
        width = flt(row.custom_client_width_mm || row.custom_dimension_width_mm);
        thickness = flt(row.custom_dimension_thickness_mm);
    }

    let new_name = base_name;

    if (length > 0 && width > 0) {
        if (thickness > 0) {
            new_name = `${base_name} ${thickness}MM [${length},${width}]`;
        } else {
            new_name = `${base_name} [${length},${width}]`;
        }
    }

    if (row.item_name !== new_name) {
        frappe.model.set_value(cdt, cdn, "item_name", new_name);
    }
}

