async function open_pending_so_line_dialog(frm) {
  const r = await frappe.call({
    method: "mat_reco.material_reconfiguration.services.repack_from_sales_order_service.get_pending_sales_order_lines_for_repack",
    args: {
      company: frm.doc.company
    },
    freeze: true,
    freeze_message: __("Loading pending sales order lines...")
  });

  const rows = (r.message || []).filter(d => flt(d.qty_pending) > 0);

  let selected = null;

  const dialog = new frappe.ui.Dialog({
    title: __("Select Sales Order Line"),
    size: "extra-large",
    fields: [
      {
        fieldname: "results_html",
        fieldtype: "HTML"
      }
    ],
    primary_action_label: __("Generate Repack"),
    primary_action: async () => {
      if (!selected) {
        frappe.msgprint(__("Please select one line."));
        return;
      }

      await frm.save();

      await frappe.call({
        method: "mat_reco.material_reconfiguration.services.repack_from_sales_order_service.generate_repack_from_sales_order_item",
        args: {
          stock_entry_name: frm.doc.name,
          sales_order_item_name: selected.sales_order_item,
          generate_qty: selected.qty_generable
        },
        freeze: true,
        freeze_message: __("Generating repack...")
      });

      dialog.hide();
      await frm.reload_doc();

      frappe.show_alert({
        message: __("Repack generated from Sales Order line."),
        indicator: "green"
      });
    }
  });

  dialog.show();

  const wrapper = dialog.get_field("results_html").$wrapper;
  wrapper.empty();

  if (!rows.length) {
    wrapper.html(`<div class="text-muted">${__("No pending Sales Order line can currently be satisfied from stock.")}</div>`);
    return;
  }

  const table = $(`
    <div style="max-height: 500px; overflow: auto;">
      <table class="table table-bordered table-hover">
        <thead>
          <tr>
            <th style="width:40px">${__("Select")}</th>
            <th>${__("Sales Order")}</th>
            <th>${__("Item Code")}</th>
            <th>${__("Item Name")}</th>
            <th>${__("Longueur")}</th>
            <th>${__("Hauteur")}</th>
            <th>${__("Epaisseur")}</th>
            <th>${__("Qty Commande")}</th>
            <th>${__("Qty Déjà Générée")}</th>
            <th>${__("Qty Restante")}</th>
            <th>${__("Qty Satisfiable")}</th>
          </tr>
        </thead>
        <tbody></tbody>
      </table>
    </div>
  `);

  wrapper.append(table);

  const tbody = table.find("tbody");

  rows.forEach((row, index) => {
    const tr = $(`
      <tr data-index="${index}" style="cursor:pointer;">
        <td><input type="radio" name="so_line_pick"></td>
        <td>${frappe.utils.escape_html(row.sales_order || "")}</td>
        <td>${frappe.utils.escape_html(row.item_code || "")}</td>
        <td>${frappe.utils.escape_html(row.item_name || "")}</td>
        <td style="text-align:right;">${format_number(row.length_mm)}</td>
        <td style="text-align:right;">${format_number(row.width_mm)}</td>
        <td style="text-align:right;">${format_number(row.thickness_mm)}</td>
        <td style="text-align:right;">${format_number(row.qty_ordered)}</td>
        <td style="text-align:right;">${format_number(row.qty_generated)}</td>
        <td style="text-align:right;">${format_number(row.qty_pending)}</td>
        <td style="text-align:right;"><b>${format_number(row.qty_generable)}</b></td>
      </tr>
    `);

    tr.on("click", function () {
      tbody.find("tr").removeClass("table-active");
      tbody.find("input[type=radio]").prop("checked", false);

      $(this).addClass("table-active");
      $(this).find("input[type=radio]").prop("checked", true);

      selected = row;
    });

    tbody.append(tr);
  });
}

function flt(v) {
  return parseFloat(v || 0);
}

function format_number(v) {
  const n = flt(v);
  return frappe.format(n, { fieldtype: "Float" });
}
